var p=msg.payload||{};
if(p.sethome){msg.payload={command:'SETHOME'};return [msg,null,null,null,null,null,null];}
if(p.routine){msg.payload={command:p.routine.toUpperCase()};return [msg,null,null,null,null,null,null];}
if(p.jog){msg.payload={axis:p.jog.slice(0,-1),dir:p.jog.slice(-1),step:p.step};return [null,msg,null,null,null,null,null];}
if(p.joint){msg.payload={joint:p.joint.slice(0,-1),dir:p.joint.slice(-1),step:p.step};return [null,null,msg,null,null,null,null];}
if(p.goto){msg.payload={name:p.goto,id:p.goto,moveType:p.moveType,storage:p.storage};return [null,null,null,msg,null,null,null];}
if(p.movej){msg.payload=p.movej;return [null,null,null,null,msg,null,null];}
if(p.stop){msg.payload={};return [null,null,null,null,null,msg,null];}
msg.statusCode=400;msg.payload={ok:false,error:'unknown command'};
return [null,null,null,null,null,null,msg];
